{final_life, total_exp} = Enum.reduce(operations, {10, 0}, fn {life_change, exp_gain}, {life, exp} ->
new_life = min(life - life_change, 10)
if new_life > 0, do: {new_life, exp + exp_gain}, else: {0, exp}
end)

